"""Stripe payment provider."""
import stripe

class StripeProvider:
    def __init__(self, api_key):
        stripe.api_key = api_key

    def checkout(self, amount, currency='usd'):
        return stripe.PaymentIntent.create(amount=amount, currency=currency)

    def refund(self, payment_id, amount=None):
        return stripe.Refund.create(payment_intent=payment_id, amount=amount)

    def handle_webhook(self, payload, sig_header):
        return stripe.Webhook.construct_event(payload, sig_header, self.webhook_secret)

"""PayPal payment provider."""
from paypalrestsdk import Payment, Refund

class PayPalProvider:
    def __init__(self, client_id, secret):
        self.client_id = client_id
        self.secret = secret

    def checkout(self, amount, currency='USD'):
        payment = Payment({"intent": "sale", "amount": {"total": amount, "currency": currency}})
        return payment.create()

    def refund(self, payment_id, amount=None):
        return Refund.create(payment_id, {"amount": amount})

    def handle_webhook(self, payload):
        return payload

"""Square payment provider."""
from square.client import Client

class SquareProvider:
    def __init__(self, access_token):
        self.client = Client(access_token=access_token)

    def checkout(self, amount, currency='USD'):
        result = self.client.payments.create_payment(
            source_id='CARD_NONCE',
            amount_money={'amount': amount, 'currency': currency}
        )
        return result

    def refund(self, payment_id, amount=None):
        result = self.client.refunds.refund_payment(
            payment_id=payment_id,
            amount_money={'amount': amount, 'currency': 'USD'}
        )
        return result

    def handle_webhook(self, payload, signature):
