"""Braintree payment provider."""
import braintree

class BraintreeProvider:
    def __init__(self, merchant_id, public_key, private_key):
        self.gateway = braintree.BraintreeGateway(
            braintree.Configuration(
                environment=braintree.Environment.Production,
                merchant_id=merchant_id,
                public_key=public_key,
                private_key=private_key
            )
        )

    def checkout(self, amount, currency='USD'):
        result = self.gateway.transaction.sale({
            "amount": amount,
            "payment_method_nonce": "nonce-from-client"
        })
        return result

    def refund(self, transaction_id, amount=None):
        result = self.gateway.transaction.refund(transaction_id, amount)
        return result

    def handle_webhook(self, bt_signature, bt_payload):
        webhook_notification = self.gateway.webhook_notification.parse(bt_signature, bt_payload)
        return webhook_notification

